return [
  { json: { company: 'Acrelec',         intelligence_type: 'Competitor Moves', time_range_days: 7 } },
  { json: { company: 'Pyramid Computer', intelligence_type: 'Competitor Moves', time_range_days: 7 } },
  { json: { company: 'Wanzl',            intelligence_type: 'Competitor Moves', time_range_days: 7 } },
  { json: { company: 'Broadsign',        intelligence_type: 'Competitor Moves', time_range_days: 7 } },
  { json: { company: 'Diebold Nixdorf',  intelligence_type: 'Competitor Moves', time_range_days: 7 } },
  { json: { company: 'LamasaTech',       intelligence_type: 'Competitor Moves', time_range_days: 7 } }
];

const items = $input.all();
const date = new Date().toLocaleDateString('en-GB', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

let allSignalsHtml = '';

for (const item of items) {
  const data = item.json;
  if (!data.competitor) continue;
  const signals = data.signals || [];

  const formatSignals = (level) => {
    const group = signals.filter(s => s.impact_level === level);
    if (!group.length) return '';
    let out = `<h4 style="color:${level==='High'?'#c0392b':level==='Medium'?'#d17a00':'#2d8a4e'};margin:8px 0 6px">${level} Impact</h4>`;
    group.forEach(s => {
      out += `<div style="border-left:3px solid ${level==='High'?'#c0392b':level==='Medium'?'#d17a00':'#2d8a4e'};padding:8px 12px;margin-bottom:8px;background:#fafafa">`;
      out += `<strong style="font-size:13px">${s.title || ''}</strong>`;
      if (s.url) out += ` <a href="${s.url}" style="color:#666;font-size:11px">[source]</a>`;
      out += `<br/><span style="color:#555;font-size:12px">${s.impact_summary || ''}</span>`;
      if (s.confidence) out += `<span style="float:right;color:#999;font-size:11px">${s.confidence}/10</span>`;
      out += '</div>';
    });
    return out;
  };

  let takeaway = data.executive_takeaway || '';
  if (takeaway.includes('── EXECUTIVE TAKEAWAY')) {
    takeaway = takeaway.split('── EXECUTIVE TAKEAWAY')[1].replace(/─+/g,'').trim();
  }

  allSignalsHtml += `
    <div style="margin-bottom:40px;border:1px solid #e4e7f0;border-radius:6px;overflow:hidden">
      <div style="background:#0f1117;color:white;padding:14px 20px">
        <strong style="font-size:16px">${data.competitor}</strong>
        <span style="color:rgba(255,255,255,0.5);font-size:12px;margin-left:12px">${data.intelligence_type} · ${signals.length} signals · ${data.llm_calls_made || 0}/7 LLM calls</span>
      </div>
      <div style="padding:16px 20px">
        ${formatSignals('High')}
        ${formatSignals('Medium')}
        ${formatSignals('Low')}
        ${takeaway ? `<div style="background:#0f1117;color:white;padding:12px 16px;border-radius:4px;margin-top:12px"><div style="font-size:10px;letter-spacing:0.1em;text-transform:uppercase;opacity:0.45;margin-bottom:4px">Executive Takeaway</div><p style="margin:0;font-size:13px;line-height:1.6;opacity:0.9">${takeaway}</p></div>` : ''}
      </div>
    </div>`;
}

const html = `
<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><style>
  body { font-family: Georgia, serif; max-width: 700px; margin: 40px auto; color: #1a1a1a; }
  h1 { font-size: 24px; border-bottom: 2px solid #1a1a1a; padding-bottom: 10px; }
  .date { color: #666; font-size: 13px; margin-bottom: 32px; }
</style></head>
<body>
  <h1>Strategic Radar — Weekly Intelligence Brief</h1>
  <div class="date">${date} · All Competitors · Competitor Moves</div>
  ${allSignalsHtml}
</body>
</html>`;

return [{ json: { html, subject: `Strategic Radar — Weekly Brief ${date}` } }];
